const j = $('When Lead Form Submitted').first().json;
const p = j.body || j;
const s = $('Set Agent Details').first().json;
return [{ json: {
  name: p.name || p.full_name || 'there',
  email: p.email || '',
  phone: p.phone || p.phone_number || '',
  budget: p.budget || p.budget_range || '',
  interest: p.interest || p.property_type || p.message || '',
  timeline: p.timeline || '',
  message: p.message || p.notes || '',
  businessName: s.businessName, agentName: s.agentName, agentEmail: s.agentEmail,
  bookingLink: s.bookingLink, aiUrl: s.aiUrl, aiModel: s.aiModel
}}];

const out = [];
for (const it of $input.all()) {
  const j = it.json;
  const prompt = 'You are the assistant for ' + j.businessName + ', a real estate agency. A new lead just came in. ' +
    'First qualify them as HOT, WARM, or COLD from budget, timeline and intent. ' +
    'Then write a warm, professional reply (4-6 sentences) from ' + (j.agentName || 'our team') + ' that thanks them, references their interest, answers helpfully, and invites them to book a viewing at this link: ' + j.bookingLink + '. ' +
    'Return ONLY JSON with keys: score (HOT|WARM|COLD), reason (one line), replySubject, replyBody. ' +
    'Lead -> name: ' + j.name + ', email: ' + j.email + ', phone: ' + j.phone + ', budget: ' + j.budget + ', interest: ' + j.interest + ', timeline: ' + j.timeline + ', message: ' + j.message;
  const aiBody = JSON.stringify({ model: j.aiModel, messages: [{ role: 'user', content: prompt }], temperature: 0.5, stream: false, response_format: { type: 'json_object' } });
  out.push({ json: { ...j, aiBody } });
}
return out;

const prep = $('Build AI Request Data').all();
const res = $input.all();
const out = [];
for (let i = 0; i < res.length; i++) {
  let txt = '';
  try { txt = res[i].json.choices[0].message.content; } catch (e) {}
  let p = { score: 'WARM', reason: '', replySubject: 'Thanks for reaching out', replyBody: '' };
  try { p = JSON.parse(txt); } catch (e) {}
  const j = (prep[i] && prep[i].json) ? prep[i].json : {};
  out.push({ json: { ...j, score: String(p.score || 'WARM').toUpperCase(), reason: p.reason || '', replySubject: p.replySubject || 'Thanks for reaching out', replyBody: p.replyBody || ('Hi ' + j.name + ', thanks for your interest! Book a viewing here: ' + j.bookingLink) } });
}
return out;

